"Hospice.Has Hospice Services" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Encounter: Encounter Inpatient" WHERE fhirpath_text(resource, 'status') IN ('finished')) AS InpatientEncounter WHERE InpatientEncounter.patient_id = p.patient_id AND (fhirpath_bool(InpatientEncounter.resource, 'hospitalization.dischargeDisposition.coding.where(system=''http://snomed.info/sct'' and code=''428361000124107'').exists()') OR fhirpath_bool(InpatientEncounter.resource, 'hospitalization.dischargeDisposition.coding.where(system=''http://snomed.info/sct'' and code=''428371000124100'').exists()')) AND CAST(intervalEnd(fhirpath_text(InpatientEncounter.resource, 'period')) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE))) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Encounter: Hospice Encounter" WHERE fhirpath_text(resource, 'status') IN ('finished')) AS HospiceEncounter WHERE HospiceEncounter.patient_id = p.patient_id AND CAST(intervalStart(fhirpath_text(HospiceEncounter.resource, 'period')) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(fhirpath_text(HospiceEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Observation: Hospice care [Minimum Data Set]" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS HospiceAssessment WHERE HospiceAssessment.patient_id = p.patient_id AND fhirpath_bool(HospiceAssessment.resource, 'value.coding.where(system=''http://snomed.info/sct'' and code=''373066001'').exists()') AND CAST(intervalStart(CASE WHEN fhirpath_text(HospiceAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospiceAssessment.resource, 'effective')), '{') THEN fhirpath_text(HospiceAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HospiceAssessment.resource, 'effective'), fhirpath_text(HospiceAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(HospiceAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospiceAssessment.resource, 'effective')), '{') THEN fhirpath_text(HospiceAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HospiceAssessment.resource, 'effective'), fhirpath_text(HospiceAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "ServiceRequest: Hospice Care Ambulatory" WHERE fhirpath_text(resource, 'status') IN ('active', 'completed') AND fhirpath_text(resource, 'intent') IN ('order', 'original-order', 'reflex-order', 'filler-order', 'instance-order')) AS HospiceOrder WHERE HospiceOrder.patient_id = p.patient_id AND CAST(fhirpath_text(HospiceOrder.resource, 'authoredOn') AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(fhirpath_text(HospiceOrder.resource, 'authoredOn') AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Procedure: Hospice Care Ambulatory" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS HospicePerformed WHERE HospicePerformed.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(HospicePerformed.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospicePerformed.resource, 'performed')), '{') THEN fhirpath_text(HospicePerformed.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(HospicePerformed.resource, 'performed'), fhirpath_text(HospicePerformed.resource, 'performed'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(HospicePerformed.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospicePerformed.resource, 'performed')), '{') THEN fhirpath_text(HospicePerformed.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(HospicePerformed.resource, 'performed'), fhirpath_text(HospicePerformed.resource, 'performed'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Condition: Hospice Diagnosis (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Hospice Diagnosis (qicore-condition-encounter-diagnosis)") AS _union WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS HospiceCareDiagnosis WHERE HospiceCareDiagnosis.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HospiceCareDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HospiceCareDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE))
),
"SDE.SDE Ethnicity" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_E -> json_object('codes', "Distinct"(list_concat([fhirpath_text(_lt_E, 'ombCategory')], fhirpath_text(_lt_E, 'detailed'))), 'display', fhirpath_text(_lt_E, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Payer" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('code', Payer.type, 'period', fhirpath_text(Payer.resource, 'period')) AS _resource_data FROM "Coverage: Payer Type" AS Payer) AS _inner
),
"SDE.SDE Race" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-race'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_R -> json_object('codes', CASE WHEN fhirpath_text(_lt_R, 'ombCategory') IS NOT NULL  AND fhirpath_text(_lt_R, 'detailed') IS NOT NULL  THEN "Distinct"(jsonConcat(fhirpath_text(_lt_R, 'ombCategory'), fhirpath_text(_lt_R, 'detailed'))) ELSE NULL END, 'display', fhirpath_text(_lt_R, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Sex" AS (
SELECT p.patient_id, (SELECT CASE WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248153007' THEN 'http://snomed.info/sct|248153007' WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248152002' THEN 'http://snomed.info/sct|248152002' ELSE NULL END) AS value FROM _patients AS p
),
"August 1 Year Prior to the Measurement Period" AS (
SELECT p.patient_id, (CAST(make_timestamp(Year(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) - INTERVAL '1 year'), 8, 1, 0, 0, CAST(0 AS DOUBLE) + CAST(0 AS DOUBLE) / 1000.0) AS VARCHAR) || printf('%+03.0f:00', CAST(0 AS DOUBLE))) AS value FROM _patients AS p
),
"Date HOOS Total Assessment Completed" AS (
SELECT HOOSLifeQuality.patient_id, CAST(list_max([intervalStart(CASE WHEN fhirpath_text(HOOSLifeQuality.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HOOSLifeQuality.resource, 'effective')), '{') THEN fhirpath_text(HOOSLifeQuality.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HOOSLifeQuality.resource, 'effective'), fhirpath_text(HOOSLifeQuality.resource, 'effective'), TRUE, TRUE) END), intervalStart(CASE WHEN fhirpath_text(HOOSSport.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HOOSSport.resource, 'effective')), '{') THEN fhirpath_text(HOOSSport.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HOOSSport.resource, 'effective'), fhirpath_text(HOOSSport.resource, 'effective'), TRUE, TRUE) END), intervalStart(CASE WHEN fhirpath_text(HOOSActivityScore.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HOOSActivityScore.resource, 'effective')), '{') THEN fhirpath_text(HOOSActivityScore.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HOOSActivityScore.resource, 'effective'), fhirpath_text(HOOSActivityScore.resource, 'effective'), TRUE, TRUE) END), intervalStart(CASE WHEN fhirpath_text(HOOSSymptoms.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HOOSSymptoms.resource, 'effective')), '{') THEN fhirpath_text(HOOSSymptoms.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HOOSSymptoms.resource, 'effective'), fhirpath_text(HOOSSymptoms.resource, 'effective'), TRUE, TRUE) END), intervalStart(CASE WHEN fhirpath_text(HOOSPain.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HOOSPain.resource, 'effective')), '{') THEN fhirpath_text(HOOSPain.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HOOSPain.resource, 'effective'), fhirpath_text(HOOSPain.resource, 'effective'), TRUE, TRUE) END)]) AS VARCHAR) AS resource FROM (SELECT patient_id, resource FROM "Observation: Quality of life score [HOOS]" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS HOOSLifeQuality CROSS JOIN (SELECT patient_id, resource FROM "Observation: Sport-recreation score [HOOS]" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS HOOSSport CROSS JOIN (SELECT patient_id, resource FROM "Observation: Activities of daily living score [HOOS]" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS HOOSActivityScore CROSS JOIN (SELECT patient_id, resource FROM "Observation: Symptoms score [HOOS]" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS HOOSSymptoms CROSS JOIN (SELECT patient_id, resource FROM "Observation: Pain score [HOOS]" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS HOOSPain WHERE CAST(intervalStart(CASE WHEN fhirpath_text(HOOSLifeQuality.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HOOSLifeQuality.resource, 'effective')), '{') THEN fhirpath_text(HOOSLifeQuality.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HOOSLifeQuality.resource, 'effective'), fhirpath_text(HOOSLifeQuality.resource, 'effective'), TRUE, TRUE) END) AS DATE) = CAST(intervalStart(CASE WHEN fhirpath_text(HOOSSport.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HOOSSport.resource, 'effective')), '{') THEN fhirpath_text(HOOSSport.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HOOSSport.resource, 'effective'), fhirpath_text(HOOSSport.resource, 'effective'), TRUE, TRUE) END) AS DATE) AND fhirpath_text(HOOSSport.resource, 'value') IS NOT NULL AND CAST(intervalStart(CASE WHEN fhirpath_text(HOOSLifeQuality.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HOOSLifeQuality.resource, 'effective')), '{') THEN fhirpath_text(HOOSLifeQuality.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HOOSLifeQuality.resource, 'effective'), fhirpath_text(HOOSLifeQuality.resource, 'effective'), TRUE, TRUE) END) AS DATE) = CAST(intervalStart(CASE WHEN fhirpath_text(HOOSActivityScore.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HOOSActivityScore.resource, 'effective')), '{') THEN fhirpath_text(HOOSActivityScore.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HOOSActivityScore.resource, 'effective'), fhirpath_text(HOOSActivityScore.resource, 'effective'), TRUE, TRUE) END) AS DATE) AND fhirpath_text(HOOSActivityScore.resource, 'value') IS NOT NULL AND CAST(intervalStart(CASE WHEN fhirpath_text(HOOSLifeQuality.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HOOSLifeQuality.resource, 'effective')), '{') THEN fhirpath_text(HOOSLifeQuality.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HOOSLifeQuality.resource, 'effective'), fhirpath_text(HOOSLifeQuality.resource, 'effective'), TRUE, TRUE) END) AS DATE) = CAST(intervalStart(CASE WHEN fhirpath_text(HOOSSymptoms.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HOOSSymptoms.resource, 'effective')), '{') THEN fhirpath_text(HOOSSymptoms.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HOOSSymptoms.resource, 'effective'), fhirpath_text(HOOSSymptoms.resource, 'effective'), TRUE, TRUE) END) AS DATE) AND fhirpath_text(HOOSSymptoms.resource, 'value') IS NOT NULL AND CAST(intervalStart(CASE WHEN fhirpath_text(HOOSLifeQuality.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HOOSLifeQuality.resource, 'effective')), '{') THEN fhirpath_text(HOOSLifeQuality.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HOOSLifeQuality.resource, 'effective'), fhirpath_text(HOOSLifeQuality.resource, 'effective'), TRUE, TRUE) END) AS DATE) = CAST(intervalStart(CASE WHEN fhirpath_text(HOOSPain.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HOOSPain.resource, 'effective')), '{') THEN fhirpath_text(HOOSPain.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HOOSPain.resource, 'effective'), fhirpath_text(HOOSPain.resource, 'effective'), TRUE, TRUE) END) AS DATE) AND fhirpath_text(HOOSPain.resource, 'value') IS NOT NULL AND fhirpath_text(HOOSLifeQuality.resource, 'value') IS NOT NULL AND HOOSSport.patient_id = HOOSLifeQuality.patient_id AND HOOSActivityScore.patient_id = HOOSLifeQuality.patient_id AND HOOSSymptoms.patient_id = HOOSLifeQuality.patient_id AND HOOSPain.patient_id = HOOSLifeQuality.patient_id
),
"Date HOOSJr Total Assessment Completed" AS (
SELECT DocumentedHOOSJr.patient_id, intervalStart(CASE WHEN fhirpath_text(DocumentedHOOSJr.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DocumentedHOOSJr.resource, 'effective')), '{') THEN fhirpath_text(DocumentedHOOSJr.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DocumentedHOOSJr.resource, 'effective'), fhirpath_text(DocumentedHOOSJr.resource, 'effective'), TRUE, TRUE) END) AS value FROM (SELECT * FROM (SELECT patient_id, resource FROM "Observation: Total interval score [HOOSJR]" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS HOOSJr WHERE fhirpath_text(HOOSJr.resource, 'value') IS NOT NULL) AS DocumentedHOOSJr
),
"Date PROMIS10 Total Assessment Completed" AS (
SELECT PROMIS10MentalScore.patient_id, CAST(list_max([intervalStart(CASE WHEN fhirpath_text(PROMIS10MentalScore.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PROMIS10MentalScore.resource, 'effective')), '{') THEN fhirpath_text(PROMIS10MentalScore.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(PROMIS10MentalScore.resource, 'effective'), fhirpath_text(PROMIS10MentalScore.resource, 'effective'), TRUE, TRUE) END), intervalStart(CASE WHEN fhirpath_text(PROMIS10PhysicalScore.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PROMIS10PhysicalScore.resource, 'effective')), '{') THEN fhirpath_text(PROMIS10PhysicalScore.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(PROMIS10PhysicalScore.resource, 'effective'), fhirpath_text(PROMIS10PhysicalScore.resource, 'effective'), TRUE, TRUE) END)]) AS VARCHAR) AS resource FROM (SELECT patient_id, resource FROM "Observation: PROMIS-10 Global Mental Health (GMH) score T-score" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS PROMIS10MentalScore CROSS JOIN (SELECT patient_id, resource FROM "Observation: PROMIS-10 Global Physical Health (GPH) score T-score" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS PROMIS10PhysicalScore WHERE CAST(intervalStart(CASE WHEN fhirpath_text(PROMIS10MentalScore.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PROMIS10MentalScore.resource, 'effective')), '{') THEN fhirpath_text(PROMIS10MentalScore.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(PROMIS10MentalScore.resource, 'effective'), fhirpath_text(PROMIS10MentalScore.resource, 'effective'), TRUE, TRUE) END) AS DATE) = CAST(intervalStart(CASE WHEN fhirpath_text(PROMIS10PhysicalScore.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PROMIS10PhysicalScore.resource, 'effective')), '{') THEN fhirpath_text(PROMIS10PhysicalScore.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(PROMIS10PhysicalScore.resource, 'effective'), fhirpath_text(PROMIS10PhysicalScore.resource, 'effective'), TRUE, TRUE) END) AS DATE) AND fhirpath_text(PROMIS10PhysicalScore.resource, 'value') IS NOT NULL AND fhirpath_text(PROMIS10MentalScore.resource, 'value') IS NOT NULL AND PROMIS10PhysicalScore.patient_id = PROMIS10MentalScore.patient_id
),
"Date VR12 Oblique Total Assessment Completed" AS (
SELECT VR12MentalAssessment.patient_id, CAST(list_max([intervalStart(CASE WHEN fhirpath_text(VR12MentalAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VR12MentalAssessment.resource, 'effective')), '{') THEN fhirpath_text(VR12MentalAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VR12MentalAssessment.resource, 'effective'), fhirpath_text(VR12MentalAssessment.resource, 'effective'), TRUE, TRUE) END), intervalStart(CASE WHEN fhirpath_text(VR12PhysicalAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VR12PhysicalAssessment.resource, 'effective')), '{') THEN fhirpath_text(VR12PhysicalAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VR12PhysicalAssessment.resource, 'effective'), fhirpath_text(VR12PhysicalAssessment.resource, 'effective'), TRUE, TRUE) END)]) AS VARCHAR) AS resource FROM (SELECT patient_id, resource FROM "Observation: VR-12 Mental component summary (MCS) score - oblique method T-score" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS VR12MentalAssessment CROSS JOIN (SELECT patient_id, resource FROM "Observation: VR-12 Physical component summary (PCS) score - oblique method T-score" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS VR12PhysicalAssessment WHERE CAST(intervalStart(CASE WHEN fhirpath_text(VR12MentalAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VR12MentalAssessment.resource, 'effective')), '{') THEN fhirpath_text(VR12MentalAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VR12MentalAssessment.resource, 'effective'), fhirpath_text(VR12MentalAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) = CAST(intervalStart(CASE WHEN fhirpath_text(VR12PhysicalAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VR12PhysicalAssessment.resource, 'effective')), '{') THEN fhirpath_text(VR12PhysicalAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VR12PhysicalAssessment.resource, 'effective'), fhirpath_text(VR12PhysicalAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) AND fhirpath_text(VR12MentalAssessment.resource, 'value') IS NOT NULL AND fhirpath_text(VR12PhysicalAssessment.resource, 'value') IS NOT NULL AND VR12PhysicalAssessment.patient_id = VR12MentalAssessment.patient_id
),
"Date VR12 Orthogonal Total Assessment Completed" AS (
SELECT VR12MentalAssessment.patient_id, CAST(list_max([intervalStart(CASE WHEN fhirpath_text(VR12MentalAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VR12MentalAssessment.resource, 'effective')), '{') THEN fhirpath_text(VR12MentalAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VR12MentalAssessment.resource, 'effective'), fhirpath_text(VR12MentalAssessment.resource, 'effective'), TRUE, TRUE) END), intervalStart(CASE WHEN fhirpath_text(VR12PhysicalAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VR12PhysicalAssessment.resource, 'effective')), '{') THEN fhirpath_text(VR12PhysicalAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VR12PhysicalAssessment.resource, 'effective'), fhirpath_text(VR12PhysicalAssessment.resource, 'effective'), TRUE, TRUE) END)]) AS VARCHAR) AS resource FROM (SELECT patient_id, resource FROM "Observation: VR-12 Mental component summary (MCS) score - orthogonal method T-score" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS VR12MentalAssessment CROSS JOIN (SELECT patient_id, resource FROM "Observation: VR-12 Physical component summary (PCS) score - orthogonal method T-score" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS VR12PhysicalAssessment WHERE CAST(intervalStart(CASE WHEN fhirpath_text(VR12MentalAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VR12MentalAssessment.resource, 'effective')), '{') THEN fhirpath_text(VR12MentalAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VR12MentalAssessment.resource, 'effective'), fhirpath_text(VR12MentalAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) = CAST(intervalStart(CASE WHEN fhirpath_text(VR12PhysicalAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VR12PhysicalAssessment.resource, 'effective')), '{') THEN fhirpath_text(VR12PhysicalAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VR12PhysicalAssessment.resource, 'effective'), fhirpath_text(VR12PhysicalAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) AND fhirpath_text(VR12MentalAssessment.resource, 'value') IS NOT NULL AND fhirpath_text(VR12PhysicalAssessment.resource, 'value') IS NOT NULL AND VR12PhysicalAssessment.patient_id = VR12MentalAssessment.patient_id
),
"Has Qualifying Encounter" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Encounter: Outpatient Consultation" UNION SELECT patient_id, resource FROM "Encounter: Office Visit" UNION (SELECT patient_id, resource FROM "Encounter" AS E WHERE fhirpath_bool(E.resource, 'type.coding.where(system=''http://www.ama-assn.org/go/cpt'' and code=''99024'').exists()')) UNION SELECT patient_id, resource FROM "Encounter: Telephone Visits" UNION SELECT patient_id, resource FROM "Encounter: Virtual Encounter") AS _union WHERE fhirpath_text(resource, 'status') IN ('finished')) AS ValidEncounters WHERE ValidEncounters.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(ValidEncounters.resource, 'period') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ValidEncounters.resource, 'period')), '{') THEN fhirpath_text(ValidEncounters.resource, 'period') ELSE intervalFromBounds(fhirpath_text(ValidEncounters.resource, 'period'), fhirpath_text(ValidEncounters.resource, 'period'), TRUE, TRUE) END) AS DATE) >= CAST((SELECT sub.value FROM "August 1 Year Prior to the Measurement Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS DATE) AND CAST(intervalEnd(CASE WHEN fhirpath_text(ValidEncounters.resource, 'period') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ValidEncounters.resource, 'period')), '{') THEN fhirpath_text(ValidEncounters.resource, 'period') ELSE intervalFromBounds(fhirpath_text(ValidEncounters.resource, 'period'), fhirpath_text(ValidEncounters.resource, 'period'), TRUE, TRUE) END) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE))
),
"Has Severe Cognitive Impairment" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Severe cognitive impairment (finding) (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Severe cognitive impairment (finding) (qicore-condition-encounter-diagnosis)") AS Dementia WHERE Dementia.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(Dementia.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(Dementia.resource, 'onsetDateTime'), fhirpath_text(Dementia.resource, 'onsetPeriod.start'), fhirpath_text(Dementia.resource, 'recordedDate')), fhirpath_text(Dementia.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(Dementia.resource, 'onsetDateTime'), fhirpath_text(Dementia.resource, 'onsetPeriod.start'), fhirpath_text(Dementia.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(Dementia.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(Dementia.resource, 'onsetDateTime'), fhirpath_text(Dementia.resource, 'onsetPeriod.start'), fhirpath_text(Dementia.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(Dementia.resource, 'onsetDateTime'), fhirpath_text(Dementia.resource, 'onsetPeriod.start'), fhirpath_text(Dementia.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(Dementia.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(Dementia.resource, 'onsetDateTime'), fhirpath_text(Dementia.resource, 'onsetPeriod.start'), fhirpath_text(Dementia.resource, 'recordedDate')), fhirpath_text(Dementia.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(Dementia.resource, 'onsetDateTime'), fhirpath_text(Dementia.resource, 'onsetPeriod.start'), fhirpath_text(Dementia.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(Dementia.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(Dementia.resource, 'onsetDateTime'), fhirpath_text(Dementia.resource, 'onsetPeriod.start'), fhirpath_text(Dementia.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(Dementia.resource, 'onsetDateTime'), fhirpath_text(Dementia.resource, 'onsetPeriod.start'), fhirpath_text(Dementia.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE))
),
"November 1 Two Years Prior to the Measurement Period" AS (
SELECT p.patient_id, (CAST(make_timestamp(Year(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) - INTERVAL '2 year'), 11, 1, 0, 0, CAST(0 AS DOUBLE) + CAST(0 AS DOUBLE) / 1000.0) AS VARCHAR) || printf('%+03.0f:00', CAST(0 AS DOUBLE))) AS value FROM _patients AS p
),
"October 31 Year Prior to the Measurement Period" AS (
SELECT p.patient_id, (CAST(make_timestamp(Year(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) - INTERVAL '1 year'), 10, 31, 23, 59, CAST(59 AS DOUBLE) + CAST(0 AS DOUBLE) / 1000.0) AS VARCHAR) || printf('%+03.0f:00', CAST(0 AS DOUBLE))) AS value FROM _patients AS p
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer Type" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
),
"Total Hip Arthroplasty Procedure" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Procedure: Primary THA Procedure" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS THAProcedure WHERE CAST(intervalStart(CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST((SELECT sub.value FROM "November 1 Two Years Prior to the Measurement Period" AS sub WHERE sub.patient_id = THAProcedure.patient_id LIMIT 1) AS VARCHAR), CAST((SELECT sub.value FROM "October 31 Year Prior to the Measurement Period" AS sub WHERE sub.patient_id = THAProcedure.patient_id LIMIT 1) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST((SELECT sub.value FROM "November 1 Two Years Prior to the Measurement Period" AS sub WHERE sub.patient_id = THAProcedure.patient_id LIMIT 1) AS VARCHAR), CAST((SELECT sub.value FROM "October 31 Year Prior to the Measurement Period" AS sub WHERE sub.patient_id = THAProcedure.patient_id LIMIT 1) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST((SELECT sub.value FROM "November 1 Two Years Prior to the Measurement Period" AS sub WHERE sub.patient_id = THAProcedure.patient_id LIMIT 1) AS VARCHAR), CAST((SELECT sub.value FROM "October 31 Year Prior to the Measurement Period" AS sub WHERE sub.patient_id = THAProcedure.patient_id LIMIT 1) AS VARCHAR), TRUE, TRUE)) AS DATE))
),
"Death Within 300 Days of the THA Procedure" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Total Hip Arthroplasty Procedure" AS THAProcedure WHERE THAProcedure.patient_id = p.patient_id AND CAST(fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = THAProcedure.patient_id LIMIT 1), 'deceased') AS DATE) >= CAST(intervalStart(CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) AND CAST(fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = THAProcedure.patient_id LIMIT 1), 'deceased') AS DATE) <= CAST(dateAddQuantity(CAST(intervalStart(CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), '{"value": 300.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE))
),
"Has Malignant Neoplasm of Lower and Unspecified Limbs" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Malignant Neoplasms of Lower and Unspecified Limbs (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Malignant Neoplasms of Lower and Unspecified Limbs (qicore-condition-encounter-diagnosis)") AS MalignantNeoplasm WHERE MalignantNeoplasm.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "Total Hip Arthroplasty Procedure") AS THAProcedure WHERE CAST(intervalStart(CASE WHEN fhirpath_text(MalignantNeoplasm.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(MalignantNeoplasm.resource, 'onsetDateTime'), fhirpath_text(MalignantNeoplasm.resource, 'onsetPeriod.start'), fhirpath_text(MalignantNeoplasm.resource, 'recordedDate')), fhirpath_text(MalignantNeoplasm.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(MalignantNeoplasm.resource, 'onsetDateTime'), fhirpath_text(MalignantNeoplasm.resource, 'onsetPeriod.start'), fhirpath_text(MalignantNeoplasm.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(MalignantNeoplasm.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(MalignantNeoplasm.resource, 'onsetDateTime'), fhirpath_text(MalignantNeoplasm.resource, 'onsetPeriod.start'), fhirpath_text(MalignantNeoplasm.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(MalignantNeoplasm.resource, 'onsetDateTime'), fhirpath_text(MalignantNeoplasm.resource, 'onsetPeriod.start'), fhirpath_text(MalignantNeoplasm.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(MalignantNeoplasm.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(MalignantNeoplasm.resource, 'onsetDateTime'), fhirpath_text(MalignantNeoplasm.resource, 'onsetPeriod.start'), fhirpath_text(MalignantNeoplasm.resource, 'recordedDate')), fhirpath_text(MalignantNeoplasm.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(MalignantNeoplasm.resource, 'onsetDateTime'), fhirpath_text(MalignantNeoplasm.resource, 'onsetPeriod.start'), fhirpath_text(MalignantNeoplasm.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(MalignantNeoplasm.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(MalignantNeoplasm.resource, 'onsetDateTime'), fhirpath_text(MalignantNeoplasm.resource, 'onsetPeriod.start'), fhirpath_text(MalignantNeoplasm.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(MalignantNeoplasm.resource, 'onsetDateTime'), fhirpath_text(MalignantNeoplasm.resource, 'onsetPeriod.start'), fhirpath_text(MalignantNeoplasm.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) AND THAProcedure.patient_id = MalignantNeoplasm.patient_id))
),
"Has Mechanical Complication" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Mechanical Complications Excluding Upper Body (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Mechanical Complications Excluding Upper Body (qicore-condition-problems-health-concerns)") AS MechanicalComplications WHERE MechanicalComplications.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "Total Hip Arthroplasty Procedure") AS THAProcedure WHERE CAST(intervalStart(CASE WHEN fhirpath_text(MechanicalComplications.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(MechanicalComplications.resource, 'onsetDateTime'), fhirpath_text(MechanicalComplications.resource, 'onsetPeriod.start'), fhirpath_text(MechanicalComplications.resource, 'recordedDate')), fhirpath_text(MechanicalComplications.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(MechanicalComplications.resource, 'onsetDateTime'), fhirpath_text(MechanicalComplications.resource, 'onsetPeriod.start'), fhirpath_text(MechanicalComplications.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(MechanicalComplications.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(MechanicalComplications.resource, 'onsetDateTime'), fhirpath_text(MechanicalComplications.resource, 'onsetPeriod.start'), fhirpath_text(MechanicalComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(MechanicalComplications.resource, 'onsetDateTime'), fhirpath_text(MechanicalComplications.resource, 'onsetPeriod.start'), fhirpath_text(MechanicalComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(MechanicalComplications.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(MechanicalComplications.resource, 'onsetDateTime'), fhirpath_text(MechanicalComplications.resource, 'onsetPeriod.start'), fhirpath_text(MechanicalComplications.resource, 'recordedDate')), fhirpath_text(MechanicalComplications.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(MechanicalComplications.resource, 'onsetDateTime'), fhirpath_text(MechanicalComplications.resource, 'onsetPeriod.start'), fhirpath_text(MechanicalComplications.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(MechanicalComplications.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(MechanicalComplications.resource, 'onsetDateTime'), fhirpath_text(MechanicalComplications.resource, 'onsetPeriod.start'), fhirpath_text(MechanicalComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(MechanicalComplications.resource, 'onsetDateTime'), fhirpath_text(MechanicalComplications.resource, 'onsetPeriod.start'), fhirpath_text(MechanicalComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) AND THAProcedure.patient_id = MechanicalComplications.patient_id))
),
"Has More Than One Elective Primary Total Hip Arthroplasty Performed" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Total Hip Arthroplasty Procedure" AS THAProcedure WHERE THAProcedure.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM "Procedure: Primary THA Procedure" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS ElectiveTHAProcedure WHERE NOT CASE WHEN fhirpath_text(THAProcedure.resource, 'id') IS NULL AND fhirpath_text(ElectiveTHAProcedure.resource, 'id') IS NULL THEN TRUE WHEN fhirpath_text(THAProcedure.resource, 'id') IS NULL OR fhirpath_text(ElectiveTHAProcedure.resource, 'id') IS NULL THEN FALSE ELSE fhirpath_text(THAProcedure.resource, 'id') = fhirpath_text(ElectiveTHAProcedure.resource, 'id') END AND CAST(intervalStart(CASE WHEN fhirpath_text(ElectiveTHAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ElectiveTHAProcedure.resource, 'performed')), '{') THEN fhirpath_text(ElectiveTHAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(ElectiveTHAProcedure.resource, 'performed'), fhirpath_text(ElectiveTHAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) >= CAST(dateSubtractQuantity(CAST(intervalStart(CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), '{"value": 1.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS DATE) AND CAST(intervalStart(CASE WHEN fhirpath_text(ElectiveTHAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ElectiveTHAProcedure.resource, 'performed')), '{') THEN fhirpath_text(ElectiveTHAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(ElectiveTHAProcedure.resource, 'performed'), fhirpath_text(ElectiveTHAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) <= CAST(dateAddQuantity(CAST(intervalStart(CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), '{"value": 1.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS DATE) AND ElectiveTHAProcedure.patient_id = THAProcedure.patient_id))
),
"Has Partial Hip Arthroplasty Procedure" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Procedure: Partial Arthroplasty of Hip" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS PartialTHAProcedure WHERE PartialTHAProcedure.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "Total Hip Arthroplasty Procedure") AS THAProcedure WHERE CAST(intervalStart(CASE WHEN fhirpath_text(PartialTHAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PartialTHAProcedure.resource, 'performed')), '{') THEN fhirpath_text(PartialTHAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(PartialTHAProcedure.resource, 'performed'), fhirpath_text(PartialTHAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) >= CAST(intervalStart(CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) AND CAST(intervalEnd(CASE WHEN fhirpath_text(PartialTHAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PartialTHAProcedure.resource, 'performed')), '{') THEN fhirpath_text(PartialTHAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(PartialTHAProcedure.resource, 'performed'), fhirpath_text(PartialTHAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) AND THAProcedure.patient_id = PartialTHAProcedure.patient_id))
),
"Has Revision Hip Arthroplasty Procedure or Implanted Device or Prosthesis Removal Procedure" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Total Hip Arthroplasty Procedure" AS THAProcedure WHERE THAProcedure.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM "Procedure: Removal, Revision and Supplement Procedures of the Lower Body and Spine" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS RevisionTHAProcedure WHERE CAST(intervalStart(CASE WHEN fhirpath_text(RevisionTHAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(RevisionTHAProcedure.resource, 'performed')), '{') THEN fhirpath_text(RevisionTHAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(RevisionTHAProcedure.resource, 'performed'), fhirpath_text(RevisionTHAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) >= CAST(intervalStart(CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) AND CAST(intervalEnd(CASE WHEN fhirpath_text(RevisionTHAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(RevisionTHAProcedure.resource, 'performed')), '{') THEN fhirpath_text(RevisionTHAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(RevisionTHAProcedure.resource, 'performed'), fhirpath_text(RevisionTHAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) AND RevisionTHAProcedure.patient_id = THAProcedure.patient_id))
),
"Has THA with Initial and Follow Up HOOS Assessments" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT CASE WHEN fhirpath_text(TotalHip.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(TotalHip.resource, 'performed')), '{') THEN fhirpath_text(TotalHip.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(TotalHip.resource, 'performed'), fhirpath_text(TotalHip.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS TotalHip WHERE TotalHip.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "Date HOOS Total Assessment Completed") AS InitialHipAssessmentHOOS WHERE CAST(CAST(InitialHipAssessmentHOOS.resource AS DATE) AS DATE) <= CAST(intervalStart((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS DATE) AND CAST(intervalStart((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS DATE) <= CAST(CAST(InitialHipAssessmentHOOS.resource AS DATE) + INTERVAL '90 day' AS DATE) AND InitialHipAssessmentHOOS.patient_id = TotalHip.patient_id) AND EXISTS (SELECT 1 FROM (SELECT * FROM "Date HOOS Total Assessment Completed") AS FollowUpHipAssessmentHOOS WHERE CAST(FollowUpHipAssessmentHOOS.resource AS DATE) >= CAST(dateAddQuantity(CAST(intervalEnd((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS VARCHAR), '{"value": 300.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND CAST(FollowUpHipAssessmentHOOS.resource AS DATE) <= CAST(dateAddQuantity(CAST(intervalEnd((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS VARCHAR), '{"value": 425.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND FollowUpHipAssessmentHOOS.patient_id = TotalHip.patient_id))
),
"Has THA with Initial and Follow Up HOOSJr Assessments" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT CASE WHEN fhirpath_text(TotalHip.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(TotalHip.resource, 'performed')), '{') THEN fhirpath_text(TotalHip.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(TotalHip.resource, 'performed'), fhirpath_text(TotalHip.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS TotalHip WHERE TotalHip.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "Date HOOSJr Total Assessment Completed") AS InitialHipAssessment WHERE CAST(CAST(InitialHipAssessment.value AS DATE) AS DATE) <= CAST(intervalStart((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS DATE) AND CAST(intervalStart((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS DATE) <= CAST(CAST(InitialHipAssessment.value AS DATE) + INTERVAL '90 day' AS DATE) AND InitialHipAssessment.patient_id = TotalHip.patient_id) AND EXISTS (SELECT 1 FROM (SELECT * FROM "Date HOOSJr Total Assessment Completed") AS FollowUpHipAssessment WHERE CAST(FollowUpHipAssessment.value AS DATE) >= CAST(dateAddQuantity(CAST(intervalEnd((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS VARCHAR), '{"value": 300.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND CAST(FollowUpHipAssessment.value AS DATE) <= CAST(dateAddQuantity(CAST(intervalEnd((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS VARCHAR), '{"value": 425.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND FollowUpHipAssessment.patient_id = TotalHip.patient_id))
),
"Has THA with Initial and Follow Up PROMIS10 Assessments" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT CASE WHEN fhirpath_text(TotalHip.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(TotalHip.resource, 'performed')), '{') THEN fhirpath_text(TotalHip.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(TotalHip.resource, 'performed'), fhirpath_text(TotalHip.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS TotalHip WHERE TotalHip.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "Date PROMIS10 Total Assessment Completed") AS InitialHipAssessmentPROMIS10 WHERE CAST(CAST(InitialHipAssessmentPROMIS10.resource AS DATE) AS DATE) <= CAST(intervalStart((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS DATE) AND CAST(intervalStart((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS DATE) <= CAST(CAST(InitialHipAssessmentPROMIS10.resource AS DATE) + INTERVAL '90 day' AS DATE) AND InitialHipAssessmentPROMIS10.patient_id = TotalHip.patient_id) AND EXISTS (SELECT 1 FROM (SELECT * FROM "Date PROMIS10 Total Assessment Completed") AS FollowUpHipAssessmentPROMIS10 WHERE CAST(FollowUpHipAssessmentPROMIS10.resource AS DATE) >= CAST(dateAddQuantity(CAST(intervalEnd((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS VARCHAR), '{"value": 300.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND CAST(FollowUpHipAssessmentPROMIS10.resource AS DATE) <= CAST(dateAddQuantity(CAST(intervalEnd((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS VARCHAR), '{"value": 425.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND FollowUpHipAssessmentPROMIS10.patient_id = TotalHip.patient_id))
),
"Has THA with Initial and Follow Up VR12 Oblique Assessments" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT CASE WHEN fhirpath_text(TotalHip.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(TotalHip.resource, 'performed')), '{') THEN fhirpath_text(TotalHip.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(TotalHip.resource, 'performed'), fhirpath_text(TotalHip.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS TotalHip WHERE TotalHip.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "Date VR12 Oblique Total Assessment Completed") AS InitialHipAssessmentOblique WHERE CAST(CAST(InitialHipAssessmentOblique.resource AS DATE) AS DATE) <= CAST(intervalStart((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS DATE) AND CAST(intervalStart((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS DATE) <= CAST(CAST(InitialHipAssessmentOblique.resource AS DATE) + INTERVAL '90 day' AS DATE) AND InitialHipAssessmentOblique.patient_id = TotalHip.patient_id) AND EXISTS (SELECT 1 FROM (SELECT * FROM "Date VR12 Oblique Total Assessment Completed") AS FollowUpHipAssessmentOblique WHERE CAST(FollowUpHipAssessmentOblique.resource AS DATE) >= CAST(dateAddQuantity(CAST(intervalEnd((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS VARCHAR), '{"value": 300.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND CAST(FollowUpHipAssessmentOblique.resource AS DATE) <= CAST(dateAddQuantity(CAST(intervalEnd((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS VARCHAR), '{"value": 425.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND FollowUpHipAssessmentOblique.patient_id = TotalHip.patient_id))
),
"Has THA with Initial and Follow Up VR12 Orthogonal Assessments" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT CASE WHEN fhirpath_text(TotalHip.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(TotalHip.resource, 'performed')), '{') THEN fhirpath_text(TotalHip.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(TotalHip.resource, 'performed'), fhirpath_text(TotalHip.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS TotalHip WHERE TotalHip.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "Date VR12 Orthogonal Total Assessment Completed") AS InitialHipAssessmentOrthogonal WHERE CAST(CAST(InitialHipAssessmentOrthogonal.resource AS DATE) AS DATE) <= CAST(intervalStart((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS DATE) AND CAST(intervalStart((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS DATE) <= CAST(CAST(InitialHipAssessmentOrthogonal.resource AS DATE) + INTERVAL '90 day' AS DATE) AND InitialHipAssessmentOrthogonal.patient_id = TotalHip.patient_id) AND EXISTS (SELECT 1 FROM (SELECT * FROM "Date VR12 Orthogonal Total Assessment Completed") AS FollowUpHipAssessmentOrthogonal WHERE CAST(FollowUpHipAssessmentOrthogonal.resource AS DATE) >= CAST(dateAddQuantity(CAST(intervalEnd((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS VARCHAR), '{"value": 300.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND CAST(FollowUpHipAssessmentOrthogonal.resource AS DATE) <= CAST(dateAddQuantity(CAST(intervalEnd((SELECT CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END FROM "Total Hip Arthroplasty Procedure" AS THAProcedure)) AS VARCHAR), '{"value": 425.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND FollowUpHipAssessmentOrthogonal.patient_id = TotalHip.patient_id))
),
"Has Total Hip Arthroplasty with 1 or More Lower Body Fractures" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Total Hip Arthroplasty Procedure" AS THAProcedure WHERE THAProcedure.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM "Condition: Lower Body Fractures Excluding Ankle and Foot (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Lower Body Fractures Excluding Ankle and Foot (qicore-condition-problems-health-concerns)") AS LowerBodyFracture WHERE CAST(intervalStart(CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) - INTERVAL '48 hour' <= CAST(intervalStart(CASE WHEN fhirpath_text(LowerBodyFracture.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(LowerBodyFracture.resource, 'onsetDateTime'), fhirpath_text(LowerBodyFracture.resource, 'onsetPeriod.start'), fhirpath_text(LowerBodyFracture.resource, 'recordedDate')), fhirpath_text(LowerBodyFracture.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(LowerBodyFracture.resource, 'onsetDateTime'), fhirpath_text(LowerBodyFracture.resource, 'onsetPeriod.start'), fhirpath_text(LowerBodyFracture.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(LowerBodyFracture.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(LowerBodyFracture.resource, 'onsetDateTime'), fhirpath_text(LowerBodyFracture.resource, 'onsetPeriod.start'), fhirpath_text(LowerBodyFracture.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(LowerBodyFracture.resource, 'onsetDateTime'), fhirpath_text(LowerBodyFracture.resource, 'onsetPeriod.start'), fhirpath_text(LowerBodyFracture.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS TIMESTAMP) AND CAST(intervalStart(CASE WHEN fhirpath_text(LowerBodyFracture.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(LowerBodyFracture.resource, 'onsetDateTime'), fhirpath_text(LowerBodyFracture.resource, 'onsetPeriod.start'), fhirpath_text(LowerBodyFracture.resource, 'recordedDate')), fhirpath_text(LowerBodyFracture.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(LowerBodyFracture.resource, 'onsetDateTime'), fhirpath_text(LowerBodyFracture.resource, 'onsetPeriod.start'), fhirpath_text(LowerBodyFracture.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(LowerBodyFracture.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(LowerBodyFracture.resource, 'onsetDateTime'), fhirpath_text(LowerBodyFracture.resource, 'onsetPeriod.start'), fhirpath_text(LowerBodyFracture.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(LowerBodyFracture.resource, 'onsetDateTime'), fhirpath_text(LowerBodyFracture.resource, 'onsetPeriod.start'), fhirpath_text(LowerBodyFracture.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS TIMESTAMP) <= CAST(intervalStart(CASE WHEN fhirpath_text(THAProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(THAProcedure.resource, 'performed')), '{') THEN fhirpath_text(THAProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(THAProcedure.resource, 'performed'), fhirpath_text(THAProcedure.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) AND LowerBodyFracture.patient_id = THAProcedure.patient_id))
),
"Denominator Exclusions" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Hospice.Has Hospice Services" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Severe Cognitive Impairment" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Total Hip Arthroplasty with 1 or More Lower Body Fractures" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Partial Hip Arthroplasty Procedure" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Revision Hip Arthroplasty Procedure or Implanted Device or Prosthesis Removal Procedure" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Malignant Neoplasm of Lower and Unspecified Limbs" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Mechanical Complication" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has More Than One Elective Primary Total Hip Arthroplasty Performed" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Death Within 300 Days of the THA Procedure" AS sub WHERE sub.patient_id = p.patient_id)
),
"Initial Population" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has Qualifying Encounter" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "Total Hip Arthroplasty Procedure" AS sub WHERE sub.patient_id = p.patient_id) AND EXTRACT(YEAR FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END >= 19
),
"Denominator" AS (
SELECT * FROM "Initial Population"
),
"Numerator" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has THA with Initial and Follow Up HOOS Assessments" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has THA with Initial and Follow Up HOOSJr Assessments" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has THA with Initial and Follow Up PROMIS10 Assessments" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has THA with Initial and Follow Up VR12 Oblique Assessments" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has THA with Initial and Follow Up VR12 Orthogonal Assessments" AS sub WHERE sub.patient_id = p.patient_id)
)
SELECT p.patient_id, (SELECT CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Initial Population", (SELECT CASE WHEN "Denominator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Denominator, (SELECT CASE WHEN "Denominator Exclusions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exclusions", (SELECT CASE WHEN "Numerator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
